3	const PROCESSING_FEE = 5;
4	
5	const NEWCOMER_FIRST_INSURANCE_PREMIUM_BY_TYPE: Record<string, number> = {
6	  sword: 110,
7	  amulet: 66,
8	  staff: 88,
9	  potion: 44,
10	  rune: 27.5,
11	};
12	
13	export type Customer = {
14	  yearsInsured: number;
15	  previousQuotes: number;
16	};
17	
18	export type Item = {
19	  type: string;
20	};
21	
22	export type QuoteInput = {
23	  items: Item[];
24	  customer: Customer;
25	};
26	
27	const premiumForItem = (item: Item): number =>
28	  NEWCOMER_FIRST_INSURANCE_PREMIUM_BY_TYPE[item.type];
29	
30	const RUNE_BLOCK_PREMIUM_WITH_FIRST_INSURANCE = 66;
31	
32	export const quote = (input: QuoteInput): number => {
33	  if (
34	    input.items.length === 3 &&
35	    input.items.every((item) => item.type === "rune")
36	  ) {
37	    return RUNE_BLOCK_PREMIUM_WITH_FIRST_INSURANCE + PROCESSING_FEE;
38	  }
39	  return input.items.reduce(
40	    (sum, item) => sum + premiumForItem(item),
41	    PROCESSING_FEE
42	  );
43	};
