const premiumForItem = (item: Item): number =>
  NEWCOMER_FIRST_INSURANCE_PREMIUM_BY_TYPE[item.type];

const RUNE_BLOCK_PREMIUM_WITH_FIRST_INSURANCE = 66;

const isRuneBlock = (items: Item[]): boolean =>
  items.length === 3 && items.every((item) => item.type === "rune");

export const quote = (input: QuoteInput): number => {
  if (isRuneBlock(input.items)) {
    return RUNE_BLOCK_PREMIUM_WITH_FIRST_INSURANCE + PROCESSING_FEE;
  }
  return input.items.reduce(
    (sum, item) => sum + premiumForItem(item),
    PROCESSING_FEE
  );
};
